select
id, user_id, order_id, wx_order_id, alipay_order_id, is_check, is_deleted, create_user, update_user,
create_time, update_time
from order_pay_type

    1 = 1 and is_deleted = 0

        and id = #{id}


        and user_id = #{userId}


        and order_id = #{orderId}


        and wx_order_id = #{wxOrderId}


        and alipay_order_id = #{alipayOrderId}


        and is_check = #{isCheck}


        and is_deleted = #{isDeleted}


        and create_user = #{createUser}


        and update_user = #{updateUser}


        and create_time = #{createTime}


        and update_time = #{updateTime}

